# Compute token F1 and longest common substring ratio
def token_f1(a,b):
    ta = a.split()
    tb = b.split()
    set_a = {}
    set_b = {}
    for t in ta:
        set_a[t] = set_a.get(t,0)+1
    for t in tb:
        set_b[t] = set_b.get(t,0)+1
    # overlap count
    overlap = 0
    for k,v in set_a.items():
        overlap += min(v, set_b.get(k,0))
    if len(ta)+len(tb)==0:
        return 0.0
    return 2*overlap/(len(ta)+len(tb))

def longest_common_substring_ratio(a,b):
    # compute LCS length in chars
    # dynamic programming
    m = len(a)
    n = len(b)
    dp = [0]*(n+1)
    longest = 0
    for i in range(1, m+1):
        newdp = [0]*(n+1)
        for j in range(1,n+1):
            if a[i-1]==b[j-1]:
                newdp[j]=dp[j-1]+1
                if newdp[j]>longest:
                    longest=newdp[j]
            else:
                newdp[j]=0
        dp = newdp
    # ratio relative to length of target maybe?
    denom = min(len(a), len(b))
    if denom==0: return 0.0
    return longest/denom

